import { test, expect } from '@playwright/test'
import { searchWith, waitForResults } from './helpers'

test.describe('Geographic features', () => {
  // ── Critical ────────────────────────────────────────────────────────

  test('enter valid ZIP code resolves location and distance appears on result cards @critical @geo', async ({
    page,
  }) => {
    await searchWith(page, { q: 'university' })
    await waitForResults(page)

    // The ZIP code input lives in the filter sidebar under "Your Location"
    const zipInput = page.getByLabel('ZIP code')
    await zipInput.fill('02134')

    // Submit the ZIP code
    await page.getByRole('button', { name: 'Go' }).click()

    // Location should resolve — the display name (e.g. "Allston, MA") replaces the input
    await expect(page.getByText(/clear location/i).or(page.getByLabel('Clear location'))).toBeVisible({
      timeout: 10_000,
    })

    // Wait for results to reload with distance data
    await waitForResults(page)

    // At least one result card should show a distance value (e.g. "< 1 mi" or "42 mi")
    const distanceElements = page.getByTestId('distance')
    await expect(distanceElements.first()).toBeVisible({ timeout: 10_000 })
  })

  // ── Standard ────────────────────────────────────────────────────────

  test('sort by distance button appears when location is set @standard @geo', async ({
    page,
  }) => {
    // Navigate with location params already set (simulates resolved ZIP)
    await searchWith(page, {
      q: 'university',
      userLat: '42.3601',
      userLng: '-71.0589',
      userState: 'MA',
    })
    await waitForResults(page)

    // The "Sort by distance" button should be visible
    await expect(
      page.getByRole('button', { name: /sort by distance/i }),
    ).toBeVisible()
  })

  test('clear location removes distance display from results @standard @geo', async ({
    page,
  }) => {
    // Start with location set so distance is displayed
    await searchWith(page, {
      q: 'university',
      userLat: '42.3601',
      userLng: '-71.0589',
      userState: 'MA',
    })
    await waitForResults(page)

    // Verify distance is showing
    const distanceElements = page.getByTestId('distance')
    await expect(distanceElements.first()).toBeVisible({ timeout: 10_000 })

    // Clear the location using the clear button (X icon with aria-label)
    await page.getByLabel('Clear location').click()

    // Wait for results to reload without distance
    await waitForResults(page)

    // Distance elements should no longer be visible
    await expect(distanceElements.first()).toBeHidden({ timeout: 10_000 })

    // Sort by distance button should also disappear
    await expect(
      page.getByRole('button', { name: /sort by distance/i }),
    ).toBeHidden()
  })

  test('click sample search card on home page navigates to /search with filters @standard @geo', async ({
    page,
  }) => {
    await page.goto('/')

    // Wait for sample search cards to render
    const sampleCards = page.getByTestId('sample-search-card')
    await expect(sampleCards.first()).toBeVisible({ timeout: 15_000 })

    // Get the href from the first visible sample card (it's a link)
    const firstCard = sampleCards.first()
    const href = await firstCard.getAttribute('href')
    expect(href).toBeTruthy()
    expect(href).toContain('/search?')

    // Click the card and verify navigation
    await firstCard.click()

    // Should navigate to /search with query params
    await expect(page).toHaveURL(/\/search\?/)

    // Results should load with the applied filters
    await waitForResults(page)
  })

  // ── Comprehensive ──────────────────────────────────────────────────

  test('invalid ZIP code handled gracefully without crash @comprehensive @geo', async ({
    page,
  }) => {
    await searchWith(page, { q: 'university' })
    await waitForResults(page)

    const zipInput = page.getByLabel('ZIP code')

    // Try a non-5-digit value
    await zipInput.fill('abc')
    await page.getByRole('button', { name: 'Go' }).click()

    // Should show an error message, not crash
    await expect(page.getByText('Enter a 5-digit ZIP code')).toBeVisible()

    // Try a 5-digit ZIP that likely doesn't exist
    await zipInput.fill('00000')
    await page.getByRole('button', { name: 'Go' }).click()

    // Should show "ZIP code not found" or similar — not crash
    await expect(
      page.getByText(/zip code not found|looking up zip/i),
    ).toBeVisible({ timeout: 10_000 })

    // Page should still be functional — results still visible
    await expect(page.getByText(/institutions found|results/i)).toBeVisible()
  })

  test('distance values are reasonable numbers @comprehensive @geo', async ({
    page,
  }) => {
    // Search with location in Boston area
    await searchWith(page, {
      q: 'university',
      userLat: '42.3601',
      userLng: '-71.0589',
      userState: 'MA',
    })
    await waitForResults(page)

    // Collect all distance text values from result cards
    const distanceElements = page.getByTestId('distance')
    await expect(distanceElements.first()).toBeVisible({ timeout: 10_000 })

    const count = await distanceElements.count()
    expect(count).toBeGreaterThan(0)

    for (let i = 0; i < count; i++) {
      const text = await distanceElements.nth(i).textContent()
      expect(text).toBeTruthy()

      // Distance text should match patterns like "< 1 mi" or "42 mi" or "1,234 mi"
      // It should NOT contain NaN, null, undefined, or negative numbers
      expect(text).not.toMatch(/NaN|null|undefined/i)
      expect(text).toMatch(/^\s*(<\s*1|[\d,]+)\s*mi\s*$/)
    }
  })
})
